	[6001] = {
		id = 6001,
		name = '石英大会黄金宝箱',
		name_tw = '石英大會黃金寶箱',
		name_en = 'Quartz Conference Golden Treasure Chest',
		name_vn = 'Hòm báu vàng Hội nghị Tinh thể thạch anh',
		name_kr = '석영 회의 황금 보물 상자',
		name_pt = 'Baú do Tesouro Dourado da Conferência de Quartzo',
		name_th = 'หีบสมบัติทองคำการประชุมควอตซ์',
		icon = 'config/item/icon_box_vs2.png',
		desc = '石英大会给予胜者的宝箱，打开可以有几率获得金币，竞技场币，好感度提升道具，潜能培养材料，饰品觉醒和升星道具等资源奖励',
		desc_tw = '石英大會給予勝者的寶箱，打開可以有幾率獲得金币、競技場幣、好感度提升道具、潛能培養材料、飾品覺醒和升星道具等資源獎勵',
		desc_en = 'The Quartz Conference prize box for winners, opening it has a chance to obtain resources such as gold coins, arena coins, favorability enhancement items, potential cultivation materials, and accessory awakening and star-up items.',
		desc_vn = 'Hòm quà dành cho người chiến thắng Hội nghị Thạch Anh, mở ra có cơ hội nhận được các phần thưởng tài nguyên như vàng, tiền xu đấu trường, vật phẩm tăng thiện cảm, nguyên liệu tu luyện tiềm năng, vật phẩm thức tỉnh và nâng cấp trang sức.',
		desc_kr = '석영 컨퍼런스 우승자 보상 상자입니다. 열면 금화, 경기장 코인, 호감도 증가 아이템, 잠재력 육성 재료, 장신구 각성 및 승급 아이템 등의 자원 보상을 얻을 확률이 있습니다.',
